<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller;use App\Models\AccountingPostingRule;use App\Support\Tenancy\TenantContext;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class AccountingPostingRuleController extends Controller{public function index():JsonResponse{return response()->json(AccountingPostingRule::query()->with(['debitAccount','creditAccount'])->orderBy('event_type')->get());}public function store(Request $request):JsonResponse{$d=$this->validated($request);return response()->json(AccountingPostingRule::query()->updateOrCreate(['event_type'=>$d['event_type']],$d),201);}public function update(Request $request,AccountingPostingRule $postingRule):JsonResponse{$postingRule->update($this->validated($request));return response()->json($postingRule->refresh());}private function validated(Request $request):array{$tenant=app(TenantContext::class)->id();$account=fn()=>Rule::exists('ledger_accounts','id')->where('cooperative_id',$tenant);return $request->validate(['event_type'=>['required','string','max:80'],'debit_account_id'=>['required','ulid',$account()],'credit_account_id'=>['required','ulid','different:debit_account_id',$account()],'description_template'=>['nullable','string','max:500'],'conditions'=>['nullable','array'],'dimensions'=>['nullable','array'],'is_active'=>['required','boolean']]);}}
